  1	import React, { FC, useState } from 'react';
  2	import produce from 'immer';
  3	
  4	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import ModalPendingChangesAlert from '@kubevirt-utils/components/PendingChanges/ModalPendingChangesAlert/ModalPendingChangesAlert';
  6	import {
  7	  getCloudInitPropagationMethod,
  8	  getPropagationMethod,
  9	} from '@kubevirt-utils/components/SSHSecretModal/utils/utils';
 10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 11	import { Radio, Split, SplitItem, Stack, StackItem } from '@patternfly/react-core';
 12	
 13	import CloudInitInfoHelper from '../CloudinitDescription/CloudinitInfoHelper';
 14	import TabModal from '../TabModal/TabModal';
 15	
 16	import { useCloudInit } from './utils/useCloudInit';
 17	import CloudinitForm from './CloudinitForm';
 18	
 19	import './cloud-init.scss';
 20	
 21	const CloudinitModal: FC<{
 22	  isOpen: boolean;
 23	  onClose: () => void;
 24	  onSubmit: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine | void>;
 25	  vm: V1VirtualMachine;
 26	  vmi?: V1VirtualMachineInstance;
 27	}> = ({ isOpen, onClose, onSubmit, vm, vmi }) => {
 28	  const { t } = useKubevirtTranslation();
 29	  const { updatedVM, updateFromYAML, ...cloudInitHookValues } = useCloudInit(vm);
 30	
 31	  const [showEditor, setShowEditor] = useState<boolean>(false);
 32	  const [isSubmitDisabled, setSubmitDisabled] = useState<boolean>(false);
 33	
 34	  const onEditorSave = (yaml: string) => {
 35	    setSubmitDisabled(false);
 36	    updateFromYAML(yaml);
 37	  };
 38	
 39	  const onSubmitModal = () => {
 40	    const updateSSHDynamicInjectionVM = produce<V1VirtualMachine>(
 41	      updatedVM,
 42	      (vmDraft: V1VirtualMachine) => {
 43	        if (getPropagationMethod(vmDraft)?.qemuGuestAgent?.users) {
 44	          vmDraft.spec.template.spec.accessCredentials[0].sshPublicKey.propagationMethod =
 45	            getCloudInitPropagationMethod(true, vmDraft);
 46	        }
 47	      },
 48	    );
 49	    return onSubmit(updateSSHDynamicInjectionVM);
 50	  };
 51	
 52	  return (
 53	    <TabModal
 54	      headerText={t('Cloud-init')}
 55	      isDisabled={isSubmitDisabled}
 56	      isOpen={isOpen}
 57	      onClose={onClose}
 58	      onSubmit={onSubmitModal}
 59	      submitBtnText={t('Apply')}
 60	    >
 61	      <Stack hasGutter>
 62	        <StackItem>{vmi && <ModalPendingChangesAlert />}</StackItem>
 63	        <CloudInitInfoHelper />
 64	        <StackItem className="kv-cloudinit--radio">
 65	          <Split hasGutter>
 66	            <SplitItem>
 67	              <strong>{t('Configure via:')}</strong>
 68	            </SplitItem>
 69	            <SplitItem>
 70	              <Radio
 71	                onChange={() => {
 72	                  setShowEditor(false);
 73	                  setSubmitDisabled(false);
 74	                }}
 75	                aria-label={'form-radio'}
 76	                id="form-radio"
 77	                isChecked={!showEditor}
 78	                label={t('Form view')}
 79	                name={'form-radio'}
 80	              />
 81	            </SplitItem>
 82	            <SplitItem>
 83	              <Radio
 84	                onChange={() => {
 85	                  setShowEditor(true);
 86	                  setSubmitDisabled(true);
 87	                }}
 88	                aria-label={'editor-radio'}
 89	                id="editor-radio"
 90	                isChecked={showEditor}
 91	                label={t('Script')}
 92	                name={'editor-radio'}
 93	              />
 94	            </SplitItem>
 95	          </Split>
 96	        </StackItem>
 97	        <CloudinitForm
 98	          onEditorSave={onEditorSave}
 99	          setSubmitDisabled={setSubmitDisabled}
100	          showEditor={showEditor}
101	          {...cloudInitHookValues}
102	        />
103	      </Stack>
104	    </TabModal>
105	  );
106	};
107	
108	export default CloudinitModal;

